// Check if Indian stock market is currently open
const now = new Date();
// Convert to IST (UTC+5:30)
const istOffset = 5.5 * 60 * 60 * 1000;
const ist = new Date(now.getTime() + istOffset + now.getTimezoneOffset() * 60 * 1000);

const day = ist.getDay(); // 0=Sun, 6=Sat
if (day === 0 || day === 6) {
  return []; // Weekend — stop execution
}

const hours = ist.getHours();
const minutes = ist.getMinutes();
const timeMinutes = hours * 60 + minutes;

// Market hours: 9:15 AM to 3:30 PM IST
const MARKET_OPEN = 9 * 60 + 15;  // 555
const MARKET_CLOSE = 15 * 60 + 30; // 930

if (timeMinutes < MARKET_OPEN || timeMinutes > MARKET_CLOSE) {
  return []; // Outside market hours — stop
}

// Check for holidays
const dateStr = ist.toISOString().split('T')[0];

return [{ json: { market_open: true, ist_time: ist.toISOString(), date: dateStr } }];

// Build batch Kite API quote request for all unique symbols
const alerts = $input.all().map(i => i.json);
const uniqueSymbols = [...new Set(alerts.map(a => `${a.exchange}:${a.symbol}`))];
const queryParams = uniqueSymbols.map(s => `i=${s}`).join('&');

return [{
  json: {
    alerts: alerts,
    quote_url: `https://api.kite.trade/quote?${queryParams}`,
    symbol_count: uniqueSymbols.length
  }
}];

// Compare live prices against all alert bounds
const quotes = $input.first().json.data || {};
const alerts = $('Build Quote Request').item.json.alerts;
const now = new Date();

const triggered = [];
const approaching = [];

for (const alert of alerts) {
  const key = `${alert.exchange}:${alert.symbol}`;
  const quote = quotes[key];
  if (!quote || !quote.last_price) continue;

  const price = quote.last_price;
  const dayChange = quote.net_change || 0;
  const volume = quote.volume || 0;

  let triggerType = null;
  let severity = 'info';
  let message = '';

  // Hard triggers
  if (alert.upper_bound && price >= parseFloat(alert.upper_bound)) {
    triggerType = 'HIT_UPPER';
    severity = 'high';
    message = `📈 *${alert.symbol}* hit ₹${price}!\n` +
              `Above your upper bound of ₹${alert.upper_bound}\n` +
              `Day change: ${dayChange >= 0 ? '+' : ''}${dayChange.toFixed(2)}`;
  } else if (alert.lower_bound && price <= parseFloat(alert.lower_bound)) {
    triggerType = 'HIT_LOWER';
    severity = 'high';
    message = `📉 *${alert.symbol}* dropped to ₹${price}!\n` +
              `Below your lower bound of ₹${alert.lower_bound}\n` +
              `Day change: ${dayChange >= 0 ? '+' : ''}${dayChange.toFixed(2)}`;
  }

  // Proximity alerts (within 1.5%)
  if (!triggerType) {
    const proximityPct = 1.5;
    if (alert.upper_bound) {
      const distPct = ((parseFloat(alert.upper_bound) - price) / price) * 100;
      if (distPct > 0 && distPct <= proximityPct) {
        triggerType = 'APPROACHING_UPPER';
        severity = 'medium';
        message = `⚡ *${alert.symbol}* at ₹${price}\n` +
                  `Only ${distPct.toFixed(1)}% from your ₹${alert.upper_bound} target`;
      }
    }
    if (!triggerType && alert.lower_bound) {
      const distPct = ((price - parseFloat(alert.lower_bound)) / price) * 100;
      if (distPct > 0 && distPct <= proximityPct) {
        triggerType = 'APPROACHING_LOWER';
        severity = 'medium';
        message = `⚠️ *${alert.symbol}* at ₹${price}\n` +
                  `Only ${distPct.toFixed(1)}% from your ₹${alert.lower_bound} floor`;
      }
    }
  }

  if (triggerType) {
    const cooldownMinutes = 30;
    const cooldownUntil = new Date(now.getTime() + cooldownMinutes * 60 * 1000);

    const result = {
      alert_id: alert.id,
      user_id: alert.user_id,
      symbol: alert.symbol,
      current_price: price,
      trigger_type: triggerType,
      severity: severity,
      message: message,
      chat_id: alert.alerts_chat_id || alert.private_chat_id,
      display_name: alert.display_name,
      upper_bound: alert.upper_bound,
      lower_bound: alert.lower_bound,
      cooldown_until: cooldownUntil.toISOString(),
      new_status: severity === 'high' 
        ? (triggerType.includes('UPPER') ? 'triggered_upper' : 'triggered_lower')
        : 'active'
    };

    if (severity === 'high') triggered.push(result);
    else approaching.push(result);
  }
}

// Return all alerts that need notification
const allAlerts = [...triggered, ...approaching];
return allAlerts.map(a => ({ json: a }));
